// Estimate quote range based on age, coverage type, and state
const data = $input.first().json;
const age = parseInt(data.age) || 50;
const coverageType = (data.coverage_type || '').toLowerCase();
const state = (data.state || 'FL').toUpperCase();
const coverageAmount = parseInt(data.coverage_amount) || 250000;

let estimatedMonthly = 0;
let quoteGuide = '';

if (coverageType.includes('life') || coverageType.includes('term')) {
  // Term life estimate (simplified)
  if (age <= 40) estimatedMonthly = coverageAmount / 1000 * 1.5;
  else if (age <= 55) estimatedMonthly = coverageAmount / 1000 * 2.5;
  else estimatedMonthly = coverageAmount / 1000 * 4.5;
  quoteGuide = 'term-life-guide';
} else if (coverageType.includes('medicare') || coverageType.includes('supplement')) {
  // Medicare supplement
  estimatedMonthly = 150 + (age - 65) * 5;
  quoteGuide = 'medicare-supplement-guide';
} else if (coverageType.includes('health')) {
  estimatedMonthly = 400 + (age - 30) * 15;
  quoteGuide = 'health-insurance-guide';
} else {
  estimatedMonthly = 300;
  quoteGuide = 'general-insurance-guide';
}

return {
  ...data,
  estimatedMonthly: Math.round(estimatedMonthly * 100) / 100,
  coverageAmount,
  quoteGuide,
  state,
  licensedState: ['FL','TX','CA','NC','SC','MI'].includes(state)
};

